class OAuthClient {
  constructor(clientId, redirectUri) {
    this.clientId = clientId;
    this.redirectUri = redirectUri;
    this.token = null;
  }

  authorize() {
    const state = Math.random().toString(36).substring(2);
    localStorage.setItem('oauthState', state);
    window.location.href = `https://authorization-server.com/oauth/authorize?response_type=token&client_id=${this.clientId}&redirect_uri=${encodeURIComponent(this.redirectUri)}&state=${state}`;
  }

  handleCallback() {
    const urlParams = new URLSearchParams(window.location.hash.substring(1));
    const state = localStorage.getItem('oauthState');
    if (urlParams.get('state') === state) {
      this.token = urlParams.get('access_token');
      localStorage.setItem('accessToken', this.token);
      window.history.replaceState({}, document.title, '/');
    } else {
      console.error('Invalid state parameter');
    }
  }

  getAccessToken() {
    if (!this.token) {
      this.token = localStorage.getItem('accessToken');
    }
    return this.token;
  }

  async makeApiCall(url, method = 'GET', data = null) {
    const token = this.getAccessToken();
    if (!token) {
      throw new Error('No access token available');
    }

    const headers = new Headers({
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    });

    const response = await fetch(url, { method, headers, body: data ? JSON.stringify(data) : null });
    if (!response.ok) {
      throw new Error(`API call failed with status ${response.status}`);
    }
    return await response.json();
  }
}

